// Set security-related HTTP headers (XSS protection, content-type sniffing, etc.)
app.use(helmet());

// CORS — configure allowed origins explicitly in production
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  methods: ['GET'],
}));

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                   // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Body parsing with size limits (for future POST/PUT routes)
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Disable X-Powered-By header (leaks framework info)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Input validation example: validate query params if filtering is added
  const { limit } = req.query;
  if (limit !== undefined) {
    const parsed = parseInt(limit, 10);
    if (isNaN(parsed) || parsed < 1 || parsed > 100) {
      return res.status(400).json({ error: 'Invalid limit parameter. Must be 1-100.' });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json(limit ? users.slice(0, parseInt(limit, 10)) : users);
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 parameters for Express to recognize it as an error handler
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Server Startup ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

